const LogoText = () => (
  <svg
    viewBox="0 0 160 40"
    xmlns="http://www.w3.org/2000/svg"
    className="DrawboardLogo-text"
  >
    <text
      x="0"
      y="30"
      fontFamily="Virgil, Segoe UI, sans-serif"
      fontSize="28"
      fill="currentColor"
      fontWeight="bold"
    >
      Drawboard
    </text>
  </svg>
);

type LogoSize = "xs" | "small" | "normal" | "large" | "custom" | "mobile";

interface LogoProps {
  size?: LogoSize;
  withText?: boolean;
  style?: React.CSSProperties;
  /**
   * If true, the logo will not be wrapped in a Link component.
   * The link prop will be ignored as well.
   * It will merely be a plain div.
   */
  isNotLink?: boolean;
}

export const DrawboardLogo = ({
  style,
  size = "small",
  withText,
}: LogoProps) => {
  return (
    <div className={`DrawboardLogo is-${size}`} style={style}>
      <LogoIcon />
      {withText && <LogoText />}
    </div>
  );
};
